input.command:
agent-browser eval "() => {
  const points = Array.from(document.querySelectorAll('path[aria-label*=\"species:\"]'));
  const speciesData = {};
  points.forEach(p => {
    const label = p.getAttribute('aria-label');
    const speciesMatch = label.match(/species: (setosa|versicolor|virginica)/);
    if (speciesMatch) {
      const species = speciesMatch[1];
      const stroke = p.getAttribute('stroke');
      if (!speciesData[species]) speciesData[species] = new Set();
      speciesData[species].add(stroke);
    }
  });
  const result = {};
  for (const s in speciesData) {
    result[s] = Array.from(speciesData[s]);
  }
  return result;
}"

agent-browser eval "() => {
  const allWithAria = Array.from(document.querySelectorAll('[aria-label]'));
  return allWithAria.slice(0, 10).map(el => ({
    tag: el.tagName,
    label: el.getAttribute('aria-label'),
    stroke: el.getAttribute('stroke'),
    fill: el.getAttribute('fill')
  }));
}"

